import React, { useState } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { Button, StatusBadge, dispatchAppToast } from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../../store/hooks';
import { useDdmhPermissions } from '../../../hooks/useDdmhPermissions';
import { purchasingService } from '../../../services/mh/purchasingService';
import type { PurchaseOrderDto } from '../../../services/mh/models';
import { ddmhPageLabels } from '../../../constants/ddmhPageLabels';
import { formatDate, formatNumber, formatMoneyVnd } from '../../../utils/formatters';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { MH_PATHS } from '../../../appPaths';
import styles from '../../../styles/erpPage.module.css';

const DdmhDetailPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const { canWrite, canConfirm, canClose } = useDdmhPermissions();
  const navigate = useNavigate();
  const { id } = useParams<{ id: string }>();
  const [data, setData] = useState<PurchaseOrderDto | null>(null);
  const [loading, setLoading] = useState(true);
  const [acting, setActing] = useState(false);

  const reload = React.useCallback(() => {
    if (!id) return;
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      purchasingService.getOrder(id)
        .then(o => { if (!cancelled) setData(o); })
        .catch(err => {
          if (!cancelled) {
            dispatchAppToast(dispatch, {
              message: getApiErrorMessage(err, ddmhPageLabels.loadError),
              type: 'error',
            });
          }
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [id, dispatch]);

  React.useEffect(() => {
    const cleanup = reload();
    return () => cleanup?.();
  }, [reload]);

  const handleConfirm = async () => {
    if (!id || !canConfirm) return;
    setActing(true);
    try {
      await purchasingService.confirmOrder(id);
      dispatchAppToast(dispatch, { message: ddmhPageLabels.confirmSuccess, type: 'success' });
      reload();
    } catch (e: unknown) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(e, ddmhPageLabels.confirmError),
        type: 'error',
      });
    } finally { setActing(false); }
  };

  const handleClose = async () => {
    if (!id || !canClose) return;
    setActing(true);
    try {
      await purchasingService.closeOrder(id);
      dispatchAppToast(dispatch, { message: ddmhPageLabels.closeSuccess, type: 'success' });
      reload();
    } catch (e: unknown) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(e, ddmhPageLabels.closeError),
        type: 'error',
      });
    } finally { setActing(false); }
  };

  if (loading || !data) {
    return (
      <div className={styles.page} data-testid="erp-mh-ddmh-detail-loading">
        <div className={styles.loading}><i className="fas fa-spinner fa-spin" /> Đang tải...</div>
      </div>
    );
  }

  return (
    <div className={styles.page} data-testid="erp-mh-ddmh-detail">
      <div className={styles.pageHeader}>
        <div className={styles.titleBlock}>
          <h1 className={styles.title}><i className="fas fa-shopping-cart" /> Đơn {data.code}</h1>
          <p className={styles.subtitle}>{formatDate(data.orderDate)} · {data.supplierName}</p>
        </div>
        <div className={styles.headerActions}>
          <Button variant="secondary" onClick={() => navigate(MH_PATHS.ddmh)}>Danh sách</Button>
          {data.status === 'Draft' && canWrite && (
            <Button variant="secondary" onClick={() => navigate(`${MH_PATHS.ddmhThem}?editId=${data.id}`)}>Sửa</Button>
          )}
          {data.status === 'Draft' && canConfirm && (
            <Button variant="primary" onClick={handleConfirm} disabled={acting}>Xác nhận</Button>
          )}
          {data.status === 'Confirmed' && canClose && (
            <Button variant="secondary" onClick={handleClose} disabled={acting}>Đóng đơn</Button>
          )}
        </div>
      </div>
      <div className={styles.summaryBar}>
        <div className={styles.summaryItem}><label className={styles.label}>Trạng thái</label><StatusBadge status={data.status} /></div>
        <div className={styles.summaryItem}><label className={styles.label}>Tổng tiền</label><strong>{formatMoneyVnd(data.totalAmount)}</strong></div>
        <div className={styles.summaryItem}><label className={styles.label}>Mô tả</label><strong>{data.description ?? '—'}</strong></div>
      </div>
      <div className={styles.tableCard}>
        <div className={styles.tableWrapper}>
          <table className={styles.table}>
            <thead><tr><th>Mã VT</th><th>ĐVT</th><th className={styles.colRight}>SL</th><th className={styles.colRight}>Đơn giá</th><th className={styles.colRight}>Thành tiền</th></tr></thead>
            <tbody>
              {data.lines.map((l, i) => (
                <tr key={l.id ?? i}>
                  <td><code>{l.materialCode}</code></td>
                  <td>{l.unitCode}</td>
                  <td className={styles.colRight}>{formatNumber(l.quantity)}</td>
                  <td className={styles.colRight}>{formatMoneyVnd(l.unitPrice)}</td>
                  <td className={styles.colRight}>{formatMoneyVnd(l.amount)}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};
export default DdmhDetailPage;
